SELECT SUM(cases) AS total_cases
FROM epidemiological_data
WHERE county_id = 1;

SELECT COUNT(*) AS total_cases, county_id
FROM case_details
GROUP BY county_id;

SELECT COUNT(*) 
FROM epidemiological_data 
WHERE cases > 0;

SELECT county_id, SUM(deaths) AS total_deaths
FROM epidemiological_data
GROUP BY county_id;

SELECT p.first_name, p.last_name, p.email
FROM patients p
INNER JOIN vaccination_records vr ON p.patient_id = vr.patient_id;
